# ── Argument order independence ──────────────────────────────────────────────


class TestArgOrder:
    def test_allow_imprecise_before_mode(self, tools, coercion_data):
        before = run_tool(
            tools["bcsvCompare"],
            "--allow-imprecise",
            "--mode",
            "values",
            coercion_data["cabove_u_a"],
            coercion_data["cabove_u_b"],
            check=False,
        )
        after = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            "--allow-imprecise",
            coercion_data["cabove_u_a"],
            coercion_data["cabove_u_b"],
            check=False,
        )
        assert before.returncode == after.returncode
        assert before.returncode == 0


