# ── Coerced values ───────────────────────────────────────────────────────────


class TestCoercedValues:
    def test_values_int_coerce(self, tools, coercion_data):
        """INT8/small-int vs UINT32 with same value — coerce mode, exit 0."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            coercion_data["cpos_a"],
            coercion_data["cpos_b"],
            check=False,
        )
        assert r.returncode == 0

    def test_values_signed_vs_unsigned_negative(self, tools, coercion_data):
        """INT(-1) vs UINT(4294967295) — std::cmp_equal returns false, exit 1."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            coercion_data["cneg"],
            coercion_data["cupos"],
            check=False,
        )
        assert r.returncode == 1

    def test_values_signed_vs_signed_same(self, tools, coercion_data):
        """INT8(-5) vs INT16(-5) — cross-type signed, must exit 0.

        This is the exact regression test for the cmpEqualInteger ternary bug:
        the old code promoted b_s to uint64_t before cmp_equal, turning -5 into
        a huge unsigned value, making cmp_equal(-5, huge) return false.
        """
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            "--rows",
            "0",  # Compare only row 0 where both are -5
            coercion_data["cneg_s8_2r"],
            coercion_data["cneg_s16_2r"],
            check=False,
        )
        assert r.returncode == 0

    def test_values_signed_vs_signed_different(self, tools, coercion_data):
        """INT8(-5) vs INT16(-32768) — cross-type signed with different values, exit 1.

        Row 0 has -5 vs -5 (match), but row 1 has -128 vs -5 (mismatch), so
        overall exit is 1.
        """
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            coercion_data["cneg_s8_2r"],
            coercion_data["cneg_s16_2r"],
            check=False,
        )
        assert r.returncode == 1

    def test_values_float_vs_double(self, tools, coercion_data):
        """FLOAT vs DOUBLE widen to double — exit 0."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            coercion_data["cflt"],
            coercion_data["cdbl"],
            check=False,
        )
        assert r.returncode == 0


