# ── String parsing edge cases ────────────────────────────────────────────────


class TestStringParsing:
    def test_string_to_value_whitespace_trimmed(self, tools, coercion_data):
        """STRING ' 12 ' vs numeric 12 — trimmed, exit 0."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            "--string-to-value",
            coercion_data["cstr_ws"],
            coercion_data["cnum"],
            check=False,
        )
        assert r.returncode == 0

    def test_string_to_value_internal_garbage_mismatch(self, tools, coercion_data):
        """STRING '12x' vs numeric 12 — not fully consumed, exit 1."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            "--string-to-value",
            coercion_data["str_garbage"],
            coercion_data["gar_num"],
            check=False,
        )
        assert r.returncode == 1

    def test_string_to_value_float(self, tools, coercion_data):
        """STRING '3.14' vs DOUBLE 3.14 — parses as float, exit 0."""
        r = run_tool(
            tools["bcsvCompare"],
            "--mode",
            "values",
            "--string-to-value",
            coercion_data["cstr_pi"],
            coercion_data["cdbl_pi"],
            check=False,
        )
        assert r.returncode == 0


